"use client";

import { FormEvent, useEffect, useMemo, useRef, useState } from "react";

type Application = { id:number; company:string; role:string; city:string; industry:string; jobCategory:string; team:string; salaryMin:number; salaryMax:number; employmentType:string; source:string; referralName:string; referralContact:string; appliedDate:string; deadlineDate:string; stage:string; priority:string; applyUrl:string; writtenDate:string; firstDate:string; secondDate:string; nextEventDate:string; responseDate:string; result:string; jdText:string; resumeId:number|null; notes:string; createdAt:string; updatedAt:string };
type Interview = { id:number; applicationId:number|null; company:string; role:string; stage:string; date:string; time:string; format:string; link:string; address:string; interviewer:string; reminderAt:string; notice:string; prep:string; review:string; createdAt:string };
type TimelineEvent = { id:number; applicationId:number; type:string; title:string; occurredAt:string; notes:string };
type KnowledgeNote = { id:number; applicationId:number|null; category:string; title:string; content:string; tags:string; createdAt:string; updatedAt:string };
type Prospect = { id:number; kind:string; company:string; role:string; city:string; tier:string; deadlineDate:string; url:string; reason:string; notes:string; createdAt:string };
type Resume = { id:number; name:string; direction:string; version:string; attachmentId:number|null; notes:string; createdAt:string };
type Attachment = { id:number; entityType:string; entityId:number|null; filename:string; contentType:string; size:number; createdAt:string };
type Offer = { id:number; applicationId:number|null; company:string; role:string; city:string; baseMonthly:number; salaryMonths:number; annualBonus:number; signOn:number; stockAnnual:number; allowanceAnnual:number; housingFundRate:number; overtimeScore:number; growthScore:number; preferenceScore:number; notes:string; createdAt:string };
type Settings = { id:number; targetCount:number; targetIndustries:string; salaryExpectation:string; reminderEnabled:boolean; reminderLeadHours:number; customTags:string };
type DataPayload = { applications:Application[]; interviews:Interview[]; timeline:TimelineEvent[]; notes:KnowledgeNote[]; prospects:Prospect[]; resumes:Resume[]; attachments:Attachment[]; offers:Offer[]; settings:Settings|null };
type PageKey = "dashboard"|"applications"|"calendar"|"knowledge"|"prospects"|"resumes"|"analysis"|"timeline"|"offers"|"settings";

const stages = ["待投递","已投递","简历评估中","笔试","一面","二面","终面","HR面","Offer","已拒绝（公司）","已回绝（本人）","流程结束"];
const funnelStages = ["已投递","笔试","一面","二面","终面","HR面","Offer"];
const priorities = ["S","A","B","C"];
const sources = ["官网","牛客","BOSS","实习僧","内推","猎头","其他"];
const noteCategories = ["面经","笔试题","话术模板","公司档案"];
const navItems:{key:PageKey;label:string;icon:string}[] = [
  {key:"dashboard",label:"总览",icon:"⌂"},{key:"applications",label:"投递记录",icon:"▤"},{key:"calendar",label:"日程",icon:"□"},{key:"knowledge",label:"知识库",icon:"◇"},{key:"prospects",label:"收藏池",icon:"☆"},{key:"resumes",label:"简历素材",icon:"▱"},{key:"analysis",label:"数据分析",icon:"⌁"},{key:"timeline",label:"秋招时间线",icon:"│"},{key:"offers",label:"Offer 对比",icon:"¥"},{key:"settings",label:"设置",icon:"⚙"},
];
const emptyApplication = { company:"",role:"",city:"",industry:"",jobCategory:"",team:"",salaryMin:0,salaryMax:0,employmentType:"全职",source:"官网",referralName:"",referralContact:"",appliedDate:"",deadlineDate:"",stage:"待投递",priority:"A",applyUrl:"",writtenDate:"",firstDate:"",secondDate:"",nextEventDate:"",responseDate:"",result:"待定",jdText:"",resumeId:null as number|null,notes:"" };
const emptyInterview = { applicationId:null as number|null,company:"",role:"",stage:"一面",date:"",time:"",format:"线上",link:"",address:"",interviewer:"",reminderAt:"",notice:"",prep:"",review:"" };
const emptyNote = { applicationId:null as number|null,category:"面经",title:"",content:"",tags:"" };
const emptyProspect = { kind:"目标公司",company:"",role:"",city:"",tier:"稳健",deadlineDate:"",url:"",reason:"",notes:"" };
const emptyResume = { name:"",direction:"",version:"V1",notes:"" };
const emptyOffer = { applicationId:null as number|null,company:"",role:"",city:"",baseMonthly:0,salaryMonths:12,annualBonus:0,signOn:0,stockAnnual:0,allowanceAnnual:0,housingFundRate:0,overtimeScore:3,growthScore:3,preferenceScore:3,notes:"" };

function cls(...values:(string|false|null|undefined)[]) { return values.filter(Boolean).join(" "); }
function todayYmd() { return new Date().toISOString().slice(0,10); }
function daysUntil(value:string) { if(!value)return null; const a=new Date();a.setHours(0,0,0,0); return Math.ceil((new Date(`${value}T00:00:00`).getTime()-a.getTime())/86400000); }
function formatDate(value:string, withYear=false) { if(!value)return "—"; const date=new Date(value.length===10?`${value}T00:00:00`:value); return new Intl.DateTimeFormat("zh-CN",{month:"short",day:"numeric",...(withYear?{year:"numeric"}:{}),weekday:"short"}).format(date); }
function money(value:number) { return new Intl.NumberFormat("zh-CN",{maximumFractionDigits:0}).format(value); }
function totalPackage(item:Offer) { return item.baseMonthly*item.salaryMonths+item.annualBonus+item.signOn+item.stockAnnual+item.allowanceAnnual; }
function initials(company:string) { return company.trim().slice(0,2) || "岗"; }
function csvEscape(value:unknown) { const text=String(value??""); return `"${text.replaceAll('"','""')}"`; }

function Modal({title,onClose,wide=false,children}:{title:string;onClose:()=>void;wide?:boolean;children:React.ReactNode}) { return <div className="modal-backdrop" onMouseDown={e=>e.target===e.currentTarget&&onClose()}><section className={cls("modal",wide&&"modal-wide")} role="dialog" aria-modal="true"><div className="modal-heading"><div><span className="section-kicker">AUTUMN DESK</span><h2>{title}</h2></div><button className="icon-button" onClick={onClose} aria-label="关闭">×</button></div>{children}</section></div>; }
function Pill({value}:{value:string}) { return <span className={cls("pill",`pill-${value.replaceAll(/[（）]/g,"").replaceAll(" ","-")}`)}>{value}</span>; }
function Empty({icon,title,copy,action}:{icon:string;title:string;copy:string;action?:React.ReactNode}) { return <div className="empty"><span>{icon}</span><h3>{title}</h3><p>{copy}</p>{action}</div>; }
function Logo({name}:{name:string}) { const hue=[174,29,210,142,252][name.length%5]; return <span className="company-logo" style={{background:`hsl(${hue} 36% 91%)`,color:`hsl(${hue} 38% 34%)`}}>{initials(name)}</span>; }

function TrendChart({applications,days}:{applications:Application[];days:number}) {
  const ref=useRef<HTMLCanvasElement>(null);
  useEffect(()=>{ const canvas=ref.current;if(!canvas)return; const rect=canvas.getBoundingClientRect();const ratio=window.devicePixelRatio||1;canvas.width=rect.width*ratio;canvas.height=rect.height*ratio;const ctx=canvas.getContext("2d");if(!ctx)return;ctx.scale(ratio,ratio);const data=Array.from({length:days},(_,i)=>{const d=new Date();d.setDate(d.getDate()-(days-1-i));const key=d.toISOString().slice(0,10);return applications.filter(a=>a.appliedDate===key).length;});const max=Math.max(2,...data);const w=rect.width,h=rect.height,p=26;ctx.clearRect(0,0,w,h);ctx.strokeStyle="#e7ece9";ctx.lineWidth=1;for(let i=0;i<4;i++){const y=p+(h-p*2)*i/3;ctx.beginPath();ctx.moveTo(p,y);ctx.lineTo(w-p,y);ctx.stroke();}ctx.strokeStyle="#348b7f";ctx.lineWidth=3;ctx.lineJoin="round";ctx.beginPath();data.forEach((v,i)=>{const x=p+(w-p*2)*i/Math.max(1,data.length-1),y=h-p-(h-p*2)*v/max;i?ctx.lineTo(x,y):ctx.moveTo(x,y);});ctx.stroke();ctx.fillStyle="#348b7f";data.forEach((v,i)=>{if(!v)return;const x=p+(w-p*2)*i/Math.max(1,data.length-1),y=h-p-(h-p*2)*v/max;ctx.beginPath();ctx.arc(x,y,4,0,Math.PI*2);ctx.fill();});ctx.fillStyle="#89968f";ctx.font="11px Arial";ctx.fillText(`${days} 天前`,p,h-5);ctx.fillText("今天",w-p-22,h-5);},[applications,days]);
  return <canvas ref={ref} className="trend-canvas" aria-label={`近${days}天投递趋势`} />;
}

function Field({label,children,wide=false}:{label:string;children:React.ReactNode;wide?:boolean}) { return <label className={wide?"span-2":""}><span>{label}</span>{children}</label>; }

export default function Home() {
  const [data,setData]=useState<DataPayload>({applications:[],interviews:[],timeline:[],notes:[],prospects:[],resumes:[],attachments:[],offers:[],settings:null});
  const [page,setPage]=useState<PageKey>("dashboard");
  const [loading,setLoading]=useState(true); const [saving,setSaving]=useState(false); const [error,setError]=useState("");
  const [mobileNav,setMobileNav]=useState(false); const [trendDays,setTrendDays]=useState(30);
  const [search,setSearch]=useState(""); const [stageFilter,setStageFilter]=useState("全部"); const [industryFilter,setIndustryFilter]=useState("全部"); const [sourceFilter,setSourceFilter]=useState("全部"); const [priorityFilter,setPriorityFilter]=useState("全部"); const [sortBy,setSortBy]=useState("最近更新");
  const [appModal,setAppModal]=useState(false); const [editApp,setEditApp]=useState<Application|null>(null); const [appForm,setAppForm]=useState(emptyApplication); const [detailApp,setDetailApp]=useState<Application|null>(null);
  const [interviewModal,setInterviewModal]=useState(false); const [editInterview,setEditInterview]=useState<Interview|null>(null); const [interviewForm,setInterviewForm]=useState(emptyInterview); const [calendarMode,setCalendarMode]=useState("月"); const [calendarDate,setCalendarDate]=useState(new Date());
  const [noteModal,setNoteModal]=useState(false); const [editNote,setEditNote]=useState<KnowledgeNote|null>(null); const [noteForm,setNoteForm]=useState(emptyNote); const [noteCategory,setNoteCategory]=useState("全部");
  const [prospectModal,setProspectModal]=useState(false); const [editProspect,setEditProspect]=useState<Prospect|null>(null); const [prospectForm,setProspectForm]=useState(emptyProspect); const [prospectKind,setProspectKind]=useState("目标公司");
  const [resumeModal,setResumeModal]=useState(false); const [resumeForm,setResumeForm]=useState(emptyResume); const [resumeFile,setResumeFile]=useState<File|null>(null);
  const [offerModal,setOfferModal]=useState(false); const [editOffer,setEditOffer]=useState<Offer|null>(null); const [offerForm,setOfferForm]=useState(emptyOffer);
  const [settingsForm,setSettingsForm]=useState<Settings>({id:1,targetCount:80,targetIndustries:"",salaryExpectation:"",reminderEnabled:true,reminderLeadHours:24,customTags:""});

  async function loadData(silent=false){ if(!silent)setLoading(true);try{const response=await fetch("/api/data",{cache:"no-store"});const payload=await response.json();if(!response.ok)throw new Error(payload.error||"数据加载失败");setData(payload);if(payload.settings)setSettingsForm(payload.settings);setError("");}catch(caught){setError(caught instanceof Error?caught.message:"连接失败，请刷新重试");}finally{setLoading(false);} }
  useEffect(()=>{void loadData();},[]);

  useEffect(()=>{ if(!settingsForm.reminderEnabled||typeof Notification==="undefined"||Notification.permission!=="granted")return;const timer=window.setInterval(()=>{const now=Date.now();data.interviews.forEach(item=>{if(!item.reminderAt)return;const key=`notified-${item.id}-${item.reminderAt}`;if(sessionStorage.getItem(key))return;const when=new Date(item.reminderAt).getTime();if(when<=now&&when>now-3600000){new Notification(`${item.company} · ${item.stage}`,{body:`${item.date} ${item.time} ${item.role}`});sessionStorage.setItem(key,"1");}});},30000);return()=>clearInterval(timer);},[data.interviews,settingsForm.reminderEnabled]);

  const appById=useMemo(()=>Object.fromEntries(data.applications.map(a=>[a.id,a])),[data.applications]);
  const industries=useMemo(()=>Array.from(new Set(data.applications.map(a=>a.industry).filter(Boolean))),[data.applications]);
  const stats=useMemo(()=>{const total=data.applications.length;const rejected=data.applications.filter(a=>a.stage.includes("拒绝")||a.result.includes("拒绝")).length;const offers=data.applications.filter(a=>a.stage==="Offer"||a.result==="Offer").length;const inFlow=data.applications.filter(a=>!["待投递","Offer","已拒绝（公司）","已回绝（本人）","流程结束"].includes(a.stage)).length;const responded=data.applications.filter(a=>!["待投递","已投递","简历评估中"].includes(a.stage)||Boolean(a.responseDate)).length;return{total,rejected,offers,inFlow,responseRate:total?Math.round(responded/total*100):0};},[data.applications]);
  const goalProgress=Math.min(100,settingsForm.targetCount?Math.round(stats.total/settingsForm.targetCount*100):0);
  const funnel=useMemo(()=>funnelStages.map((stage,index)=>{const target=stages.indexOf(stage);const count=data.applications.filter(app=>{const current=stages.indexOf(app.stage);if(current>=target&&current<=stages.indexOf("Offer"))return true;return data.timeline.some(event=>event.applicationId===app.id&&event.title.includes(stage));}).length;const previous=index?undefined:data.applications.filter(a=>a.stage!=="待投递").length;return{stage,count,rate:Math.round(count/Math.max(1,index?0:previous||1)*100)};}),[data.applications,data.timeline]);
  const funnelWithRates=funnel.map((item,index)=>({...item,rate:index?Math.round(item.count/Math.max(1,funnel[index-1].count)*100):100}));
  const distributions=useMemo(()=>{const group=(field:keyof Application)=>{const map=new Map<string,number>();data.applications.forEach(a=>{const key=String(a[field]||"未填写");map.set(key,(map.get(key)||0)+1);});return [...map.entries()].sort((a,b)=>b[1]-a[1]);};return{industry:group("industry"),job:group("jobCategory"),city:group("city"),source:group("source")};},[data.applications]);
  const todos=useMemo(()=>{const today=todayYmd();const interviews=data.interviews.filter(i=>i.date===today).map(i=>({type:i.stage,title:`${i.company} · ${i.role}`,time:i.time||"时间待定",tone:"teal"}));const deadlines=[...data.applications.map(a=>({a,days:daysUntil(a.deadlineDate)})),...data.prospects.map(p=>({a:{company:p.company,role:p.role} as Application,days:daysUntil(p.deadlineDate)}))].filter(x=>x.days!==null&&x.days!<0&&x.days!<=3).map(x=>({type:"截止",title:`${x.a.company} · ${x.a.role}`,time:x.days===0?"今天截止":`${x.days} 天后截止`,tone:"orange"}));const follow=data.applications.filter(a=>a.stage==="已投递"&&daysUntil(a.appliedDate)!< -7).slice(0,4).map(a=>({type:"跟进",title:`${a.company} · ${a.role}`,time:"投递超过 7 天",tone:"gold"}));return[...interviews,...deadlines,...follow];},[data.applications,data.interviews,data.prospects]);
  const filteredApps=useMemo(()=>data.applications.filter(a=>{const q=search.toLowerCase();return(!q||[a.company,a.role,a.city,a.industry,a.jobCategory,a.jdText,a.notes].join(" ").toLowerCase().includes(q))&&(stageFilter==="全部"||a.stage===stageFilter)&&(industryFilter==="全部"||a.industry===industryFilter)&&(sourceFilter==="全部"||a.source===sourceFilter)&&(priorityFilter==="全部"||a.priority===priorityFilter);}).sort((a,b)=>{if(sortBy==="投递时间")return(b.appliedDate||"").localeCompare(a.appliedDate||"");if(sortBy==="面试时间")return(a.nextEventDate||"9999").localeCompare(b.nextEventDate||"9999");if(sortBy==="薪资")return(b.salaryMax||0)-(a.salaryMax||0);return(b.updatedAt||"").localeCompare(a.updatedAt||"");}),[data.applications,industryFilter,priorityFilter,search,sortBy,sourceFilter,stageFilter]);

  async function requestJson(url:string,method:string,body?:unknown){setSaving(true);setError("");try{const response=await fetch(url,{method,headers:body?{"Content-Type":"application/json"}:undefined,body:body?JSON.stringify(body):undefined});const payload=await response.json();if(!response.ok)throw new Error(payload.error||"操作失败");await loadData(true);return payload;}catch(caught){setError(caught instanceof Error?caught.message:"操作失败");throw caught;}finally{setSaving(false);}}
  async function deleteItem(url:string,label:string){if(!confirm(`确定删除${label}吗？`))return;await requestJson(url,"DELETE");}

  function openApp(item?:Application){setEditApp(item||null);setAppForm(item?{...item}:emptyApplication);setAppModal(true);}
  async function saveApp(e:FormEvent){e.preventDefault();await requestJson("/api/applications",editApp?"PATCH":"POST",editApp?{...appForm,id:editApp.id}:appForm);setAppModal(false);}
  async function switchStage(item:Application,stage:string){await requestJson("/api/applications","PATCH",{...item,stage});setDetailApp({...item,stage});}
  function openInterview(item?:Interview){setEditInterview(item||null);setInterviewForm(item?{...item}:emptyInterview);setInterviewModal(true);}
  async function saveInterview(e:FormEvent){e.preventDefault();await requestJson("/api/interviews",editInterview?"PATCH":"POST",editInterview?{...interviewForm,id:editInterview.id}:interviewForm);setInterviewModal(false);}
  function openNote(item?:KnowledgeNote){setEditNote(item||null);setNoteForm(item?{...item}:emptyNote);setNoteModal(true);}
  async function saveNote(e:FormEvent){e.preventDefault();await requestJson("/api/notes",editNote?"PATCH":"POST",editNote?{...noteForm,id:editNote.id}:noteForm);setNoteModal(false);}
  function openProspect(item?:Prospect){setEditProspect(item||null);setProspectForm(item?{...item}: {...emptyProspect,kind:prospectKind});setProspectModal(true);}
  async function saveProspect(e:FormEvent){e.preventDefault();await requestJson("/api/prospects",editProspect?"PATCH":"POST",editProspect?{...prospectForm,id:editProspect.id}:prospectForm);setProspectModal(false);}
  async function saveResume(e:FormEvent){e.preventDefault();setSaving(true);try{const created=await requestJson("/api/resumes","POST",resumeForm);if(resumeFile){const form=new FormData();form.append("file",resumeFile);form.append("entityType","resume");form.append("entityId",String(created.item.id));const response=await fetch("/api/files",{method:"POST",body:form});const upload=await response.json();if(!response.ok)throw new Error(upload.error||"文件上传失败");await requestJson("/api/resumes","PATCH",{...created.item,attachmentId:upload.item.id});}setResumeModal(false);setResumeFile(null);setResumeForm(emptyResume);await loadData(true);}catch(caught){setError(caught instanceof Error?caught.message:"保存失败");}finally{setSaving(false);}}
  function openOffer(item?:Offer){setEditOffer(item||null);setOfferForm(item?{...item}:emptyOffer);setOfferModal(true);}
  async function saveOffer(e:FormEvent){e.preventDefault();await requestJson("/api/offers",editOffer?"PATCH":"POST",editOffer?{...offerForm,id:editOffer.id}:offerForm);setOfferModal(false);}
  async function uploadApplicationFile(file:File,applicationId:number){const form=new FormData();form.append("file",file);form.append("entityType","application");form.append("entityId",String(applicationId));setSaving(true);try{const response=await fetch("/api/files",{method:"POST",body:form});const payload=await response.json();if(!response.ok)throw new Error(payload.error||"上传失败");await loadData(true);}catch(caught){setError(caught instanceof Error?caught.message:"上传失败");}finally{setSaving(false);}}
  async function addTimeline(e:FormEvent<HTMLFormElement>,applicationId:number){e.preventDefault();const form=new FormData(e.currentTarget);await requestJson("/api/timeline","POST",{applicationId,type:"自定义节点",title:form.get("title"),occurredAt:form.get("occurredAt"),notes:form.get("notes")});e.currentTarget.reset();}
  async function saveSettings(e:FormEvent){e.preventDefault();await requestJson("/api/settings","PUT",settingsForm);}

  function exportCsv(){const headers=["公司名称","岗位名称","城市","行业","岗位类型","薪资下限","薪资上限","工作类型","投递渠道","投递日期","截止日期","当前状态","优先级","岗位链接","结果","备注"];const rows=data.applications.map(a=>[a.company,a.role,a.city,a.industry,a.jobCategory,a.salaryMin,a.salaryMax,a.employmentType,a.source,a.appliedDate,a.deadlineDate,a.stage,a.priority,a.applyUrl,a.result,a.notes]);const csv=[headers,...rows].map(row=>row.map(csvEscape).join(",")).join("\n");const blob=new Blob(["\uFEFF"+csv],{type:"text/csv;charset=utf-8"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=`秋招投递备份-${todayYmd()}.csv`;a.click();URL.revokeObjectURL(url);}
  async function importCsv(file:File){const text=await file.text();const lines=text.replace(/^\uFEFF/,"").split(/\r?\n/).filter(Boolean);if(lines.length<2)return;const parse=(line:string)=>{const out:string[]=[];let cur="",quoted=false;for(let i=0;i<line.length;i++){const ch=line[i];if(ch==='"'){if(quoted&&line[i+1]==='"'){cur+='"';i++;}else quoted=!quoted;}else if(ch===","&&!quoted){out.push(cur);cur="";}else cur+=ch;}out.push(cur);return out;};const headers=parse(lines[0]);const map:Record<string,keyof typeof emptyApplication>={"公司名称":"company","岗位名称":"role","城市":"city","行业":"industry","岗位类型":"jobCategory","薪资下限":"salaryMin","薪资上限":"salaryMax","工作类型":"employmentType","投递渠道":"source","投递日期":"appliedDate","截止日期":"deadlineDate","当前状态":"stage","优先级":"priority","岗位链接":"applyUrl","结果":"result","备注":"notes"};setSaving(true);try{for(const line of lines.slice(1)){const values=parse(line);const item={...emptyApplication} as Record<string,unknown>;headers.forEach((header,index)=>{const key=map[header];if(key)item[key]=["salaryMin","salaryMax"].includes(key)?Number(values[index])||0:values[index]||"";});if(item.company&&item.role){const response=await fetch("/api/applications",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(item)});if(!response.ok)throw new Error("导入中断，请检查表格格式");}}await loadData(true);}catch(caught){setError(caught instanceof Error?caught.message:"导入失败");}finally{setSaving(false);}}
  async function enableNotifications(){if(typeof Notification==="undefined"){setError("当前浏览器不支持通知");return;}const permission=await Notification.requestPermission();if(permission!=="granted")setError("通知权限未开启，可在浏览器设置中允许通知");else setError("");}

  const pageTitle=navItems.find(n=>n.key===page)?.label||"总览";
  return <div className="app-shell">
    <aside className={cls("sidebar",mobileNav&&"open")}><div className="sidebar-brand"><span>秋</span><div><strong>秋招管家</strong><small>CAREER OS</small></div></div><nav>{navItems.map(item=><button key={item.key} className={cls(page===item.key&&"active")} onClick={()=>{setPage(item.key);setMobileNav(false)}}><i>{item.icon}</i>{item.label}{item.key==="calendar"&&todos.length>0&&<b>{todos.length}</b>}</button>)}</nav><div className="goal-card"><div><span>秋招目标</span><strong>{stats.total}/{settingsForm.targetCount}</strong></div><div className="goal-track"><i style={{width:`${goalProgress}%`}}/></div><small>已完成 {goalProgress}%</small></div></aside>
    <main className="main"><header className="topbar"><button className="menu-button" onClick={()=>setMobileNav(!mobileNav)}>☰</button><div><span className="section-kicker">AUTUMN RECRUITMENT</span><h1>{pageTitle}</h1></div><div className="top-actions"><span className={cls("sync",!loading&&"ready")}><i/>{loading?"正在同步":"云端已同步"}</span><button className="avatar">我</button></div></header>{error&&<div className="error-banner">{error}<button onClick={()=>setError("")}>×</button></div>}
      {loading?<div className="loading-page"><span/><p>正在同步你的秋招数据…</p></div>:<>
      {page==="dashboard"&&<section className="page dashboard-page"><div className="welcome"><div><p>{new Date().getHours()<12?"早上好":"继续加油"}，今天也在向理想 Offer 靠近。</p><span>{todos.length?`有 ${todos.length} 项事情值得关注。`:"今天没有紧急事项，可以专注准备。"}</span></div><button className="primary" onClick={()=>openApp()}>＋ 新增投递</button></div><div className="metric-grid">{[{label:"累计投递",value:stats.total,sub:`目标 ${settingsForm.targetCount} 份`,tone:"navy"},{label:"流程中",value:stats.inFlow,sub:"正在推进",tone:"teal"},{label:"已获 Offer",value:stats.offers,sub:"继续保持",tone:"green"},{label:"已拒",value:stats.rejected,sub:"每次都是反馈",tone:"coral"},{label:"响应率",value:`${stats.responseRate}%`,sub:"收到笔试/面试反馈",tone:"gold"}].map(card=><article className={cls("metric",`metric-${card.tone}`)} key={card.label}><span>{card.label}</span><strong>{card.value}</strong><small>{card.sub}</small></article>)}</div><div className="dashboard-grid"><article className="panel funnel-panel"><div className="panel-head"><div><span className="section-kicker">CONVERSION</span><h2>投递进度漏斗</h2></div><small>阶段转化率</small></div><div className="funnel">{funnelWithRates.map((item,index)=><div className="funnel-row" key={item.stage}><span>{item.stage}</span><div><i style={{width:`${Math.max(7,item.count/Math.max(1,funnelWithRates[0].count)*100)}%`}}/></div><strong>{item.count}</strong><small>{index?`${item.rate}%`:'基准'}</small></div>)}</div></article><article className="panel trend-panel"><div className="panel-head"><div><span className="section-kicker">TREND</span><h2>投递趋势</h2></div><div className="segmented"><button className={trendDays===7?"active":""} onClick={()=>setTrendDays(7)}>7天</button><button className={trendDays===30?"active":""} onClick={()=>setTrendDays(30)}>30天</button></div></div><TrendChart applications={data.applications} days={trendDays}/></article><article className="panel distribution-panel"><div className="panel-head"><div><span className="section-kicker">DISTRIBUTION</span><h2>投递分布</h2></div></div><div className="distribution-columns">{[{name:"投递渠道",rows:distributions.source},{name:"城市",rows:distributions.city}].map(group=><div key={group.name}><h3>{group.name}</h3>{group.rows.slice(0,5).map(([name,count])=><div className="mini-bar" key={name}><span>{name}</span><div><i style={{width:`${count/Math.max(1,group.rows[0]?.[1]||1)*100}%`}}/></div><b>{count}</b></div>)}</div>)}</div></article><article className="panel todo-panel"><div className="panel-head"><div><span className="section-kicker">TODAY</span><h2>今日待办</h2></div><button onClick={()=>setPage("calendar")}>查看日历 →</button></div>{todos.length?<div className="todo-list">{todos.slice(0,6).map((todo,index)=><div key={`${todo.title}-${index}`}><i className={`dot-${todo.tone}`}/><div><strong>{todo.title}</strong><span>{todo.type} · {todo.time}</span></div></div>)}</div>:<Empty icon="✓" title="今天没有紧急事项" copy="留一点时间复盘，或者为下一场面试蓄力。"/>}</article></div></section>}

      {page==="applications"&&<section className="page"><div className="page-head"><div><p>管理从收藏、投递到 Offer 的完整生命周期。</p></div><div className="head-actions"><button className="secondary" onClick={()=>document.getElementById("csv-import")?.click()}>⇧ 导入</button><input id="csv-import" hidden type="file" accept=".csv" onChange={e=>e.target.files?.[0]&&void importCsv(e.target.files[0])}/><button className="primary" onClick={()=>openApp()}>＋ 新增投递</button></div></div><div className="filterbar"><div className="search"><span>⌕</span><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="搜索公司、岗位或关键词"/></div><select value={stageFilter} onChange={e=>setStageFilter(e.target.value)}><option>全部</option>{stages.map(x=><option key={x}>{x}</option>)}</select><select value={industryFilter} onChange={e=>setIndustryFilter(e.target.value)}><option>全部</option>{industries.map(x=><option key={x}>{x}</option>)}</select><select value={sourceFilter} onChange={e=>setSourceFilter(e.target.value)}><option>全部</option>{sources.map(x=><option key={x}>{x}</option>)}</select><select value={priorityFilter} onChange={e=>setPriorityFilter(e.target.value)}><option>全部</option>{priorities.map(x=><option key={x}>{x}</option>)}</select><select value={sortBy} onChange={e=>setSortBy(e.target.value)}>{["最近更新","投递时间","面试时间","薪资"].map(x=><option key={x}>{x}</option>)}</select></div><div className="list-summary"><span>共 {filteredApps.length} 条记录</span><span>点击记录查看完整时间线</span></div>{filteredApps.length?<div className="table-card"><table><thead><tr><th>公司 / 岗位</th><th>城市</th><th>状态</th><th>优先级</th><th>最近更新</th><th>下次节点</th><th>薪资</th><th/></tr></thead><tbody>{filteredApps.map(item=><tr key={item.id} onClick={()=>setDetailApp(item)}><td><div className="company-cell"><Logo name={item.company}/><div><strong>{item.company}</strong><span>{item.role} · {item.employmentType}</span></div></div></td><td>{item.city||"—"}</td><td><Pill value={item.stage}/></td><td><span className={cls("priority",`priority-${item.priority}`)}>{item.priority}</span></td><td>{formatDate(item.updatedAt)}</td><td>{item.nextEventDate?formatDate(item.nextEventDate):"待安排"}</td><td>{item.salaryMax?`${item.salaryMin}-${item.salaryMax}K` : "面议"}</td><td><button className="more" onClick={e=>{e.stopPropagation();openApp(item)}}>编辑</button></td></tr>)}</tbody></table></div>:<Empty icon="▤" title="还没有匹配的投递" copy="新增第一条记录，或者调整筛选条件。" action={<button className="primary" onClick={()=>openApp()}>＋ 新增投递</button>}/>}</section>}

      {page==="calendar"&&<CalendarPage interviews={data.interviews} applications={data.applications} mode={calendarMode} setMode={setCalendarMode} date={calendarDate} setDate={setCalendarDate} onAdd={()=>openInterview()} onEdit={openInterview} onDelete={id=>void deleteItem(`/api/interviews?id=${id}`,"这条日程")}/>} 

      {page==="knowledge"&&<section className="page"><div className="page-head"><div><p>沉淀面试问题、笔试题、话术和公司调研，越投越从容。</p></div><button className="primary" onClick={()=>openNote()}>＋ 新建笔记</button></div><div className="category-tabs"><button className={noteCategory==="全部"?"active":""} onClick={()=>setNoteCategory("全部")}>全部 <span>{data.notes.length}</span></button>{noteCategories.map(category=><button className={noteCategory===category?"active":""} key={category} onClick={()=>setNoteCategory(category)}>{category} <span>{data.notes.filter(n=>n.category===category).length}</span></button>)}</div>{data.notes.filter(n=>noteCategory==="全部"||n.category===noteCategory).length?<div className="note-grid">{data.notes.filter(n=>noteCategory==="全部"||n.category===noteCategory).map(note=><article className="note-card" key={note.id} onClick={()=>openNote(note)}><div><Pill value={note.category}/><button className="more" onClick={e=>{e.stopPropagation();void deleteItem(`/api/notes?id=${note.id}`,"这篇笔记")}}>⋯</button></div><h3>{note.title}</h3><p>{note.content||"还没有正文内容"}</p><footer><span>{note.applicationId&&appById[note.applicationId]?`${appById[note.applicationId].company} · ${appById[note.applicationId].role}`:"通用笔记"}</span><span>{note.tags||"未添加标签"}</span></footer></article>)}</div>:<Empty icon="◇" title="知识库还是空的" copy="每次面试后花 5 分钟复盘，会越来越有价值。" action={<button className="primary" onClick={()=>openNote()}>＋ 写第一篇笔记</button>}/>}</section>}

      {page==="prospects"&&<section className="page"><div className="page-head"><div><p>把想投、准备投和需要避雷的公司统一放进候选池。</p></div><button className="primary" onClick={()=>openProspect()}>＋ 添加目标</button></div><div className="category-tabs">{["目标公司","岗位收藏","黑名单"].map(kind=><button className={prospectKind===kind?"active":""} key={kind} onClick={()=>setProspectKind(kind)}>{kind} <span>{data.prospects.filter(p=>p.kind===kind).length}</span></button>)}</div><div className="prospect-grid">{data.prospects.filter(p=>p.kind===prospectKind).map(item=>{const days=daysUntil(item.deadlineDate);return <article className="prospect-card" key={item.id}><div className="prospect-top"><Logo name={item.company}/><div><Pill value={item.tier}/><button className="more" onClick={()=>openProspect(item)}>编辑</button></div></div><h3>{item.company}</h3><p>{item.role||item.reason||"暂未补充说明"}</p><div className={cls("deadline-card",days!==null&&days<=3&&days>=0&&"urgent")}>{item.deadlineDate?<><strong>{days!<0?"已截止":days===0?"今天截止":`${days} 天后截止`}</strong><span>{item.deadlineDate}</span></>:<span>未设置截止时间</span>}</div><footer><span>{item.city||"城市待定"} · {item.tier}</span><button onClick={()=>void deleteItem(`/api/prospects?id=${item.id}`,"这条收藏")}>删除</button></footer></article>})}{!data.prospects.some(p=>p.kind===prospectKind)&&<Empty icon="☆" title={`暂无${prospectKind}`} copy="看到合适的公司或岗位，先放进来再统一安排投递。" action={<button className="primary" onClick={()=>openProspect()}>＋ 添加目标</button>}/>}</div></section>}

      {page==="resumes"&&<section className="page"><div className="page-head"><div><p>管理不同方向的简历版本，投递时记录使用了哪一版。</p></div><button className="primary" onClick={()=>setResumeModal(true)}>＋ 新增版本</button></div><div className="resume-grid">{data.resumes.map(resume=>{const attachment=data.attachments.find(a=>a.id===resume.attachmentId);const used=data.applications.filter(a=>a.resumeId===resume.id).length;return <article className="resume-card" key={resume.id}><div className="file-icon">PDF</div><div className="resume-body"><span>{resume.direction||"通用方向"}</span><h3>{resume.name}</h3><p>{resume.version} · 已用于 {used} 次投递</p>{resume.notes&&<small>{resume.notes}</small>}</div><div className="resume-actions">{attachment&&<a href={`/api/files?id=${attachment.id}`}>下载</a>}<button onClick={()=>void deleteItem(`/api/resumes?id=${resume.id}`,"这个简历版本")}>删除</button></div></article>})}{!data.resumes.length&&<Empty icon="▱" title="还没有简历版本" copy="上传产品、运营、开发等不同方向的简历，投递时就不会弄混。" action={<button className="primary" onClick={()=>setResumeModal(true)}>＋ 新增版本</button>}/>}</div></section>}

      {page==="analysis"&&<AnalysisPage applications={data.applications} timeline={data.timeline} distributions={distributions} funnel={funnelWithRates}/>} 
      {page==="timeline"&&<TimelinePage events={data.timeline} applications={data.applications}/>} 
      {page==="offers"&&<section className="page"><div className="page-head"><div><p>折算总包并对比城市、强度、成长空间和个人意愿。</p></div><button className="primary" onClick={()=>openOffer()}>＋ 录入 Offer</button></div>{data.offers.length?<div className="offer-grid">{[...data.offers].sort((a,b)=>totalPackage(b)-totalPackage(a)).map((offer,index)=><article className={cls("offer-card",index===0&&"best")} key={offer.id}><div className="offer-rank">{index===0?"综合领先":`#${index+1}`}<button className="more" onClick={()=>openOffer(offer)}>编辑</button></div><div className="offer-company"><Logo name={offer.company}/><div><h3>{offer.company}</h3><p>{offer.role} · {offer.city}</p></div></div><div className="package"><span>估算年总包</span><strong>¥ {money(totalPackage(offer))}</strong></div><div className="offer-breakdown"><span>月薪 × 月数 <b>{money(offer.baseMonthly)} × {offer.salaryMonths}</b></span><span>奖金 / 签字费 <b>{money(offer.annualBonus+offer.signOn)}</b></span><span>股票 / 补贴 <b>{money(offer.stockAnnual+offer.allowanceAnnual)}</b></span><span>公积金比例 <b>{offer.housingFundRate}%</b></span></div><div className="score-row"><span>强度 <b>{offer.overtimeScore}/5</b></span><span>成长 <b>{offer.growthScore}/5</b></span><span>意愿 <b>{offer.preferenceScore}/5</b></span></div><button className="danger-link" onClick={()=>void deleteItem(`/api/offers?id=${offer.id}`,"这个 Offer")}>删除</button></article>)}</div>:<Empty icon="¥" title="期待你的第一个 Offer" copy="拿到 Offer 后录入薪资、奖金、股票和主观评分，方便横向比较。" action={<button className="primary" onClick={()=>openOffer()}>＋ 录入 Offer</button>}/>}</section>}

      {page==="settings"&&<section className="page settings-page"><form onSubmit={saveSettings}><div className="settings-section"><div><span className="section-kicker">GOALS</span><h2>个人目标</h2><p>让仪表盘知道你想去哪里。</p></div><div className="settings-fields"><Field label="目标投递数"><input type="number" min="0" value={settingsForm.targetCount} onChange={e=>setSettingsForm({...settingsForm,targetCount:Number(e.target.value)})}/></Field><Field label="期望薪资"><input value={settingsForm.salaryExpectation} onChange={e=>setSettingsForm({...settingsForm,salaryExpectation:e.target.value})} placeholder="例如 25-35K"/></Field><Field label="目标行业" wide><input value={settingsForm.targetIndustries} onChange={e=>setSettingsForm({...settingsForm,targetIndustries:e.target.value})} placeholder="互联网、AI、新能源（用逗号分隔）"/></Field></div></div><div className="settings-section"><div><span className="section-kicker">REMINDERS</span><h2>提醒偏好</h2><p>浏览器打开时，在设定时间提醒笔试和面试。</p></div><div className="settings-fields"><Field label="提醒开关"><select value={settingsForm.reminderEnabled?"开启":"关闭"} onChange={e=>setSettingsForm({...settingsForm,reminderEnabled:e.target.value==="开启"})}><option>开启</option><option>关闭</option></select></Field><Field label="默认提前小时"><input type="number" min="1" value={settingsForm.reminderLeadHours} onChange={e=>setSettingsForm({...settingsForm,reminderLeadHours:Number(e.target.value)})}/></Field><button type="button" className="secondary span-2" onClick={()=>void enableNotifications()}>允许浏览器通知</button></div></div><div className="settings-section"><div><span className="section-kicker">TAGS</span><h2>自定义标签</h2><p>维护行业、岗位和个人分类标签。</p></div><div className="settings-fields"><Field label="标签（逗号分隔）" wide><textarea rows={4} value={settingsForm.customTags} onChange={e=>setSettingsForm({...settingsForm,customTags:e.target.value})} placeholder="Dream、急招、校友内推…"/></Field></div></div><div className="settings-save"><button className="primary" disabled={saving}>{saving?"保存中…":"保存设置"}</button></div></form><div className="settings-section data-section"><div><span className="section-kicker">DATA</span><h2>数据备份</h2><p>导出 CSV 到本地，或导入之前的投递表。</p></div><div className="data-actions"><button className="secondary" onClick={exportCsv}>↓ 导出 CSV</button><label className="secondary upload-label">↑ 导入 CSV<input hidden type="file" accept=".csv" onChange={e=>e.target.files?.[0]&&void importCsv(e.target.files[0])}/></label></div></div></section>}
      </>}
    </main>

    {appModal&&<Modal title={editApp?"编辑投递":"新增投递"} onClose={()=>setAppModal(false)} wide><form className="form" onSubmit={saveApp}><div className="form-section-title">基础信息</div><div className="form-grid"><Field label="公司名称"><input required value={appForm.company} onChange={e=>setAppForm({...appForm,company:e.target.value})}/></Field><Field label="岗位名称"><input required value={appForm.role} onChange={e=>setAppForm({...appForm,role:e.target.value})}/></Field><Field label="工作城市"><input value={appForm.city} onChange={e=>setAppForm({...appForm,city:e.target.value})}/></Field><Field label="行业"><input value={appForm.industry} onChange={e=>setAppForm({...appForm,industry:e.target.value})} placeholder="互联网 / 金融 / 新能源"/></Field><Field label="岗位类型"><input value={appForm.jobCategory} onChange={e=>setAppForm({...appForm,jobCategory:e.target.value})} placeholder="产品 / 运营 / 开发"/></Field><Field label="工作类型"><select value={appForm.employmentType} onChange={e=>setAppForm({...appForm,employmentType:e.target.value})}><option>全职</option><option>实习</option></select></Field><Field label="薪资下限（K）"><input type="number" min="0" value={appForm.salaryMin} onChange={e=>setAppForm({...appForm,salaryMin:Number(e.target.value)})}/></Field><Field label="薪资上限（K）"><input type="number" min="0" value={appForm.salaryMax} onChange={e=>setAppForm({...appForm,salaryMax:Number(e.target.value)})}/></Field></div><div className="form-section-title">投递与进度</div><div className="form-grid"><Field label="投递渠道"><select value={appForm.source} onChange={e=>setAppForm({...appForm,source:e.target.value})}>{sources.map(x=><option key={x}>{x}</option>)}</select></Field><Field label="当前状态"><select value={appForm.stage} onChange={e=>setAppForm({...appForm,stage:e.target.value})}>{stages.map(x=><option key={x}>{x}</option>)}</select></Field><Field label="优先级"><select value={appForm.priority} onChange={e=>setAppForm({...appForm,priority:e.target.value})}>{priorities.map(x=><option key={x}>{x}</option>)}</select></Field><Field label="简历版本"><select value={appForm.resumeId||""} onChange={e=>setAppForm({...appForm,resumeId:Number(e.target.value)||null})}><option value="">未关联</option>{data.resumes.map(r=><option key={r.id} value={r.id}>{r.name} · {r.version}</option>)}</select></Field><Field label="投递日期"><input type="date" value={appForm.appliedDate} onChange={e=>setAppForm({...appForm,appliedDate:e.target.value})}/></Field><Field label="网申截止"><input type="date" value={appForm.deadlineDate} onChange={e=>setAppForm({...appForm,deadlineDate:e.target.value})}/></Field><Field label="下次节点"><input type="datetime-local" value={appForm.nextEventDate} onChange={e=>setAppForm({...appForm,nextEventDate:e.target.value})}/></Field><Field label="响应日期"><input type="date" value={appForm.responseDate} onChange={e=>setAppForm({...appForm,responseDate:e.target.value})}/></Field><Field label="内推人"><input value={appForm.referralName} onChange={e=>setAppForm({...appForm,referralName:e.target.value})}/></Field><Field label="联系方式"><input value={appForm.referralContact} onChange={e=>setAppForm({...appForm,referralContact:e.target.value})}/></Field><Field label="岗位链接" wide><input type="url" value={appForm.applyUrl} onChange={e=>setAppForm({...appForm,applyUrl:e.target.value})}/></Field></div><div className="form-section-title">补充信息</div><div className="form-grid"><Field label="JD 原文" wide><textarea rows={5} value={appForm.jdText} onChange={e=>setAppForm({...appForm,jdText:e.target.value})}/></Field><Field label="备注" wide><textarea rows={3} value={appForm.notes} onChange={e=>setAppForm({...appForm,notes:e.target.value})}/></Field></div><div className="form-actions"><button type="button" className="secondary" onClick={()=>setAppModal(false)}>取消</button><button className="primary" disabled={saving}>{saving?"保存中…":"保存投递"}</button></div></form></Modal>}

    {detailApp&&<ApplicationDetail app={detailApp} timeline={data.timeline.filter(t=>t.applicationId===detailApp.id)} notes={data.notes.filter(n=>n.applicationId===detailApp.id)} attachments={data.attachments.filter(a=>a.entityType==="application"&&a.entityId===detailApp.id)} resumes={data.resumes} onClose={()=>setDetailApp(null)} onEdit={()=>{setDetailApp(null);openApp(detailApp)}} onStage={(stage)=>void switchStage(detailApp,stage)} onDelete={()=>void deleteItem(`/api/applications?id=${detailApp.id}`,"这条投递记录").then(()=>setDetailApp(null))} onAddTimeline={addTimeline} onUpload={uploadApplicationFile}/>} 

    {interviewModal&&<Modal title={editInterview?"编辑日程":"新增笔面试日程"} onClose={()=>setInterviewModal(false)}><form className="form" onSubmit={saveInterview}><div className="form-grid"><Field label="关联投递"><select value={interviewForm.applicationId||""} onChange={e=>{const id=Number(e.target.value)||null;const app=id?appById[id]:null;setInterviewForm({...interviewForm,applicationId:id,company:app?.company||interviewForm.company,role:app?.role||interviewForm.role})}}><option value="">不关联</option>{data.applications.map(a=><option value={a.id} key={a.id}>{a.company} · {a.role}</option>)}</select></Field><Field label="公司名称"><input required value={interviewForm.company} onChange={e=>setInterviewForm({...interviewForm,company:e.target.value})}/></Field><Field label="岗位名称"><input value={interviewForm.role} onChange={e=>setInterviewForm({...interviewForm,role:e.target.value})}/></Field><Field label="面试轮次"><select value={interviewForm.stage} onChange={e=>setInterviewForm({...interviewForm,stage:e.target.value})}>{["笔试","群面","一面","二面","终面","HR面","其他"].map(x=><option key={x}>{x}</option>)}</select></Field><Field label="日期"><input type="date" required value={interviewForm.date} onChange={e=>setInterviewForm({...interviewForm,date:e.target.value})}/></Field><Field label="时间"><input type="time" value={interviewForm.time} onChange={e=>setInterviewForm({...interviewForm,time:e.target.value})}/></Field><Field label="形式"><select value={interviewForm.format} onChange={e=>setInterviewForm({...interviewForm,format:e.target.value})}>{["线上","线下","电话","其他"].map(x=><option key={x}>{x}</option>)}</select></Field><Field label="面试官"><input value={interviewForm.interviewer} onChange={e=>setInterviewForm({...interviewForm,interviewer:e.target.value})}/></Field><Field label="会议链接"><input value={interviewForm.link} onChange={e=>setInterviewForm({...interviewForm,link:e.target.value})}/></Field><Field label="地址"><input value={interviewForm.address} onChange={e=>setInterviewForm({...interviewForm,address:e.target.value})}/></Field><Field label="提醒时间" wide><input type="datetime-local" value={interviewForm.reminderAt} onChange={e=>setInterviewForm({...interviewForm,reminderAt:e.target.value})}/></Field><Field label="注意事项" wide><textarea rows={2} value={interviewForm.notice} onChange={e=>setInterviewForm({...interviewForm,notice:e.target.value})}/></Field><Field label="准备重点" wide><textarea rows={3} value={interviewForm.prep} onChange={e=>setInterviewForm({...interviewForm,prep:e.target.value})}/></Field><Field label="结果 / 复盘" wide><textarea rows={3} value={interviewForm.review} onChange={e=>setInterviewForm({...interviewForm,review:e.target.value})}/></Field></div><div className="form-actions"><button type="button" className="secondary" onClick={()=>setInterviewModal(false)}>取消</button><button className="primary" disabled={saving}>{saving?"保存中…":"保存日程"}</button></div></form></Modal>}

    {noteModal&&<Modal title={editNote?"编辑笔记":"新建知识笔记"} onClose={()=>setNoteModal(false)}><form className="form" onSubmit={saveNote}><div className="form-grid"><Field label="类型"><select value={noteForm.category} onChange={e=>setNoteForm({...noteForm,category:e.target.value})}>{noteCategories.map(x=><option key={x}>{x}</option>)}</select></Field><Field label="关联投递"><select value={noteForm.applicationId||""} onChange={e=>setNoteForm({...noteForm,applicationId:Number(e.target.value)||null})}><option value="">通用笔记</option>{data.applications.map(a=><option value={a.id} key={a.id}>{a.company} · {a.role}</option>)}</select></Field><Field label="标题" wide><input required value={noteForm.title} onChange={e=>setNoteForm({...noteForm,title:e.target.value})}/></Field><Field label="正文" wide><textarea rows={10} value={noteForm.content} onChange={e=>setNoteForm({...noteForm,content:e.target.value})} placeholder="问题、回答思路、反馈和自我复盘…"/></Field><Field label="标签" wide><input value={noteForm.tags} onChange={e=>setNoteForm({...noteForm,tags:e.target.value})} placeholder="产品、AI、项目复盘（逗号分隔）"/></Field></div><div className="form-actions"><button type="button" className="secondary" onClick={()=>setNoteModal(false)}>取消</button><button className="primary" disabled={saving}>保存笔记</button></div></form></Modal>}

    {prospectModal&&<Modal title={editProspect?"编辑收藏":"添加目标"} onClose={()=>setProspectModal(false)}><form className="form" onSubmit={saveProspect}><div className="form-grid"><Field label="类型"><select value={prospectForm.kind} onChange={e=>setProspectForm({...prospectForm,kind:e.target.value})}>{["目标公司","岗位收藏","黑名单"].map(x=><option key={x}>{x}</option>)}</select></Field><Field label="意向等级"><select value={prospectForm.tier} onChange={e=>setProspectForm({...prospectForm,tier:e.target.value})}>{["Dream","稳健","保底","避雷"].map(x=><option key={x}>{x}</option>)}</select></Field><Field label="公司名称"><input required value={prospectForm.company} onChange={e=>setProspectForm({...prospectForm,company:e.target.value})}/></Field><Field label="岗位"><input value={prospectForm.role} onChange={e=>setProspectForm({...prospectForm,role:e.target.value})}/></Field><Field label="城市"><input value={prospectForm.city} onChange={e=>setProspectForm({...prospectForm,city:e.target.value})}/></Field><Field label="网申截止"><input type="date" value={prospectForm.deadlineDate} onChange={e=>setProspectForm({...prospectForm,deadlineDate:e.target.value})}/></Field><Field label="链接" wide><input type="url" value={prospectForm.url} onChange={e=>setProspectForm({...prospectForm,url:e.target.value})}/></Field><Field label="收藏 / 避雷原因" wide><textarea rows={3} value={prospectForm.reason} onChange={e=>setProspectForm({...prospectForm,reason:e.target.value})}/></Field><Field label="备注" wide><textarea rows={3} value={prospectForm.notes} onChange={e=>setProspectForm({...prospectForm,notes:e.target.value})}/></Field></div><div className="form-actions"><button type="button" className="secondary" onClick={()=>setProspectModal(false)}>取消</button><button className="primary">保存</button></div></form></Modal>}

    {resumeModal&&<Modal title="新增简历版本" onClose={()=>setResumeModal(false)}><form className="form" onSubmit={saveResume}><div className="form-grid"><Field label="简历名称"><input required value={resumeForm.name} onChange={e=>setResumeForm({...resumeForm,name:e.target.value})} placeholder="产品经理简历"/></Field><Field label="版本号"><input value={resumeForm.version} onChange={e=>setResumeForm({...resumeForm,version:e.target.value})}/></Field><Field label="投递方向" wide><input value={resumeForm.direction} onChange={e=>setResumeForm({...resumeForm,direction:e.target.value})} placeholder="产品 / 运营 / 开发"/></Field><Field label="上传文件（最大 15MB）" wide><input type="file" accept=".pdf,.doc,.docx,.ppt,.pptx" onChange={e=>setResumeFile(e.target.files?.[0]||null)}/></Field><Field label="版本说明" wide><textarea rows={4} value={resumeForm.notes} onChange={e=>setResumeForm({...resumeForm,notes:e.target.value})}/></Field></div><div className="form-actions"><button type="button" className="secondary" onClick={()=>setResumeModal(false)}>取消</button><button className="primary" disabled={saving}>{saving?"上传中…":"保存版本"}</button></div></form></Modal>}

    {offerModal&&<Modal title={editOffer?"编辑 Offer":"录入 Offer"} onClose={()=>setOfferModal(false)}><form className="form" onSubmit={saveOffer}><div className="form-grid"><Field label="关联投递"><select value={offerForm.applicationId||""} onChange={e=>{const id=Number(e.target.value)||null;const app=id?appById[id]:null;setOfferForm({...offerForm,applicationId:id,company:app?.company||offerForm.company,role:app?.role||offerForm.role,city:app?.city||offerForm.city})}}><option value="">不关联</option>{data.applications.map(a=><option value={a.id} key={a.id}>{a.company} · {a.role}</option>)}</select></Field><Field label="公司"><input required value={offerForm.company} onChange={e=>setOfferForm({...offerForm,company:e.target.value})}/></Field><Field label="岗位"><input value={offerForm.role} onChange={e=>setOfferForm({...offerForm,role:e.target.value})}/></Field><Field label="城市"><input value={offerForm.city} onChange={e=>setOfferForm({...offerForm,city:e.target.value})}/></Field><Field label="月薪（元）"><input type="number" value={offerForm.baseMonthly} onChange={e=>setOfferForm({...offerForm,baseMonthly:Number(e.target.value)})}/></Field><Field label="薪资月数"><input type="number" step="0.5" value={offerForm.salaryMonths} onChange={e=>setOfferForm({...offerForm,salaryMonths:Number(e.target.value)})}/></Field><Field label="年终奖"><input type="number" value={offerForm.annualBonus} onChange={e=>setOfferForm({...offerForm,annualBonus:Number(e.target.value)})}/></Field><Field label="签字费"><input type="number" value={offerForm.signOn} onChange={e=>setOfferForm({...offerForm,signOn:Number(e.target.value)})}/></Field><Field label="年度股票"><input type="number" value={offerForm.stockAnnual} onChange={e=>setOfferForm({...offerForm,stockAnnual:Number(e.target.value)})}/></Field><Field label="年度补贴"><input type="number" value={offerForm.allowanceAnnual} onChange={e=>setOfferForm({...offerForm,allowanceAnnual:Number(e.target.value)})}/></Field><Field label="公积金比例 %"><input type="number" step="0.1" value={offerForm.housingFundRate} onChange={e=>setOfferForm({...offerForm,housingFundRate:Number(e.target.value)})}/></Field><Field label="加班友好度 1-5"><input type="number" min="1" max="5" value={offerForm.overtimeScore} onChange={e=>setOfferForm({...offerForm,overtimeScore:Number(e.target.value)})}/></Field><Field label="发展空间 1-5"><input type="number" min="1" max="5" value={offerForm.growthScore} onChange={e=>setOfferForm({...offerForm,growthScore:Number(e.target.value)})}/></Field><Field label="个人意愿 1-5"><input type="number" min="1" max="5" value={offerForm.preferenceScore} onChange={e=>setOfferForm({...offerForm,preferenceScore:Number(e.target.value)})}/></Field><Field label="备注" wide><textarea rows={3} value={offerForm.notes} onChange={e=>setOfferForm({...offerForm,notes:e.target.value})}/></Field></div><div className="package-preview">估算年总包 <strong>¥ {money(totalPackage(offerForm as Offer))}</strong></div><div className="form-actions"><button type="button" className="secondary" onClick={()=>setOfferModal(false)}>取消</button><button className="primary">保存 Offer</button></div></form></Modal>}
  </div>;
}

function CalendarPage({interviews,applications,mode,setMode,date,setDate,onAdd,onEdit,onDelete}:{interviews:Interview[];applications:Application[];mode:string;setMode:(v:string)=>void;date:Date;setDate:(v:Date)=>void;onAdd:()=>void;onEdit:(i:Interview)=>void;onDelete:(id:number)=>void}) {
  const year=date.getFullYear(),month=date.getMonth();const first=new Date(year,month,1);const days=new Date(year,month+1,0).getDate();const offset=(first.getDay()+6)%7;const cells=Array.from({length:42},(_,i)=>{const day=i-offset+1;return day>0&&day<=days?day:null;});const upcoming=interviews.filter(i=>i.date&&new Date(`${i.date}T${i.time||"00:00"}`).getTime()>=Date.now()).sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time)).slice(0,5);const eventsFor=(day:number)=>interviews.filter(i=>i.date===`${year}-${String(month+1).padStart(2,"0")}-${String(day).padStart(2,"0")}`);const changeMonth=(delta:number)=>setDate(new Date(year,month+delta,1));const start=new Date();start.setHours(0,0,0,0);const range=mode==="日"?1:7;const agenda=interviews.filter(i=>{const d=new Date(`${i.date}T00:00:00`);return d>=start&&d<new Date(start.getTime()+range*86400000);});return <section className="page"><div className="page-head"><div><p>集中管理笔试、面试和截止日期，避免错过重要节点。</p></div><button className="primary" onClick={onAdd}>＋ 新增日程</button></div><div className="calendar-layout"><div className="calendar-main panel"><div className="calendar-toolbar"><div><button onClick={()=>changeMonth(-1)}>‹</button><strong>{year} 年 {month+1} 月</strong><button onClick={()=>changeMonth(1)}>›</button></div><div className="segmented">{["月","周","日"].map(x=><button className={mode===x?"active":""} onClick={()=>setMode(x)} key={x}>{x}</button>)}</div></div>{mode==="月"?<div className="month-grid">{["一","二","三","四","五","六","日"].map(x=><b key={x}>{x}</b>)}{cells.map((day,index)=><div className={cls(day===new Date().getDate()&&month===new Date().getMonth()&&year===new Date().getFullYear()&&"today")} key={index}>{day&&<><span>{day}</span>{eventsFor(day).slice(0,3).map(event=><button className="calendar-event" key={event.id} onClick={()=>onEdit(event)}>{event.time} {event.company}</button>)}</>}</div>)}</div>:<div className="agenda">{agenda.length?agenda.map(event=><article key={event.id} onClick={()=>onEdit(event)}><time>{formatDate(event.date)}<strong>{event.time||"待定"}</strong></time><div><Pill value={event.stage}/><h3>{event.company} · {event.role}</h3><p>{event.format} {event.interviewer&&`· 面试官 ${event.interviewer}`}</p></div><button onClick={e=>{e.stopPropagation();onDelete(event.id)}}>删除</button></article>):<Empty icon="□" title={`未来${range}天没有安排`} copy="可以趁这段时间整理面经和准备材料。"/>}</div>}</div><aside className="upcoming panel"><div className="panel-head"><div><span className="section-kicker">UP NEXT</span><h2>即将到来</h2></div></div>{upcoming.length?upcoming.map(item=>{const ms=new Date(`${item.date}T${item.time||"00:00"}`).getTime()-Date.now();const hours=Math.max(0,Math.floor(ms/3600000));return <article key={item.id} onClick={()=>onEdit(item)}><div className="countdown"><strong>{hours<24?hours:Math.ceil(hours/24)}</strong><span>{hours<24?"小时":"天"}</span></div><div><Pill value={item.stage}/><h3>{item.company}</h3><p>{item.role}</p><small>{formatDate(item.date)} · {item.time||"待定"}</small></div></article>}):<Empty icon="◷" title="暂无安排" copy="新增笔试或面试后，会显示倒计时。"/>}<div className="deadline-list"><h3>网申截止</h3>{applications.filter(a=>{const d=daysUntil(a.deadlineDate);return d!==null&&d>=0&&d<=14;}).sort((a,b)=>(a.deadlineDate||"").localeCompare(b.deadlineDate||"")).slice(0,5).map(a=><div key={a.id}><span>{a.company} · {a.role}</span><b>{daysUntil(a.deadlineDate)} 天</b></div>)}</div></aside></div></section>;
}

function ApplicationDetail({app,timeline,notes,attachments,resumes,onClose,onEdit,onStage,onDelete,onAddTimeline,onUpload}:{app:Application;timeline:TimelineEvent[];notes:KnowledgeNote[];attachments:Attachment[];resumes:Resume[];onClose:()=>void;onEdit:()=>void;onStage:(stage:string)=>void;onDelete:()=>void;onAddTimeline:(e:FormEvent<HTMLFormElement>,id:number)=>void;onUpload:(file:File,id:number)=>void}) {const resume=resumes.find(r=>r.id===app.resumeId);return <Modal title={`${app.company} · ${app.role}`} onClose={onClose} wide><div className="detail"><div className="detail-hero"><Logo name={app.company}/><div><Pill value={app.stage}/><h3>{app.company}</h3><p>{app.role} · {app.city||"城市待定"} · {app.employmentType}</p></div><button className="secondary" onClick={onEdit}>编辑资料</button></div><section><span className="section-kicker">STATUS FLOW</span><h3>状态流转</h3><div className="status-flow">{stages.map(stage=><button className={app.stage===stage?"active":""} key={stage} onClick={()=>onStage(stage)}>{stage}</button>)}</div></section><div className="detail-grid"><section><span className="section-kicker">INFORMATION</span><h3>投递信息</h3><dl><div><dt>行业 / 岗位类型</dt><dd>{app.industry||"—"} / {app.jobCategory||"—"}</dd></div><div><dt>薪资范围</dt><dd>{app.salaryMax?`${app.salaryMin}-${app.salaryMax}K` : "面议"}</dd></div><div><dt>投递渠道</dt><dd>{app.source||"—"}</dd></div><div><dt>投递日期</dt><dd>{app.appliedDate||"—"}</dd></div><div><dt>内推人</dt><dd>{app.referralName||"—"} {app.referralContact}</dd></div><div><dt>简历版本</dt><dd>{resume?`${resume.name} · ${resume.version}`:"未关联"}</dd></div></dl>{app.jdText&&<details><summary>查看 JD 原文</summary><p>{app.jdText}</p></details>}{app.notes&&<div className="detail-note">{app.notes}</div>}</section><section><span className="section-kicker">TIMELINE</span><h3>完整时间线</h3><div className="timeline-mini">{[...timeline].sort((a,b)=>b.occurredAt.localeCompare(a.occurredAt)).map(event=><div key={event.id}><i/><time>{formatDate(event.occurredAt,true)}</time><strong>{event.title}</strong>{event.notes&&<p>{event.notes}</p>}</div>)}{!timeline.length&&<p>还没有节点记录。</p>}</div><form className="inline-event" onSubmit={e=>void onAddTimeline(e,app.id)}><input name="title" required placeholder="新增节点，例如：收到笔试通知"/><input name="occurredAt" type="datetime-local"/><input name="notes" placeholder="补充说明"/><button className="secondary">添加节点</button></form></section></div><div className="detail-grid"><section><span className="section-kicker">KNOWLEDGE</span><h3>关联面经与笔记</h3>{notes.length?notes.map(note=><div className="linked-item" key={note.id}><Pill value={note.category}/><strong>{note.title}</strong><p>{note.content}</p></div>):<p className="muted">暂无关联笔记，可在知识库中创建。</p>}</section><section><span className="section-kicker">FILES</span><h3>附件与素材</h3><div className="file-list">{attachments.map(file=><a key={file.id} href={`/api/files?id=${file.id}`}>{file.filename}<span>{Math.ceil(file.size/1024)} KB ↓</span></a>)}</div><label className="upload-box">＋ 上传简历、作品集或截图<input hidden type="file" onChange={e=>e.target.files?.[0]&&onUpload(e.target.files[0],app.id)}/></label></section></div><div className="detail-actions"><button className="danger" onClick={onDelete}>删除投递</button><button className="primary" onClick={onClose}>完成</button></div></div></Modal>}

function AnalysisPage({applications,timeline,distributions,funnel}:{applications:Application[];timeline:TimelineEvent[];distributions:{industry:[string,number][];job:[string,number][];city:[string,number][];source:[string,number][]};funnel:{stage:string;count:number;rate:number}[]}) {const avgResponse=(()=>{const values=applications.filter(a=>a.appliedDate&&a.responseDate).map(a=>(new Date(a.responseDate).getTime()-new Date(a.appliedDate).getTime())/86400000);return values.length?(values.reduce((a,b)=>a+b,0)/values.length).toFixed(1):"—";})();const channelRows=distributions.source.map(([name,count])=>{const apps=applications.filter(a=>(a.source||"未填写")===name);const interviews=apps.filter(a=>stages.indexOf(a.stage)>=stages.indexOf("笔试")&&stages.indexOf(a.stage)<=stages.indexOf("Offer")).length;const offers=apps.filter(a=>a.stage==="Offer"||a.result==="Offer").length;return{name,count,response:Math.round(interviews/Math.max(1,count)*100),offer:Math.round(offers/Math.max(1,count)*100)};});return <section className="page"><div className="page-head"><div><p>用通过率和响应时效定位薄弱环节，调整投递策略。</p></div></div><div className="analysis-metrics"><article><span>平均响应时长</span><strong>{avgResponse}{avgResponse!=="—"&&" 天"}</strong><small>从投递到首次反馈</small></article><article><span>日均投递</span><strong>{applications.length?(applications.length/Math.max(1,new Set(applications.map(a=>a.appliedDate).filter(Boolean)).size)).toFixed(1):"0"}</strong><small>有投递记录的日期</small></article><article><span>流程节点</span><strong>{timeline.length}</strong><small>累计状态与自定义事件</small></article></div><div className="analysis-grid"><article className="panel"><div className="panel-head"><div><span className="section-kicker">FUNNEL</span><h2>各阶段通过率</h2></div></div><div className="analysis-funnel">{funnel.map((item,index)=><div key={item.stage}><div><span>{item.stage}</span><b>{item.count} 人</b></div><div><i style={{width:`${item.count/Math.max(1,funnel[0].count)*100}%`}}/></div><small>{index?`上一阶段转化 ${item.rate}%`:"投递基准"}</small></div>)}</div></article><article className="panel"><div className="panel-head"><div><span className="section-kicker">CHANNELS</span><h2>渠道效果对比</h2></div></div><table className="compact-table"><thead><tr><th>渠道</th><th>投递</th><th>面试率</th><th>Offer率</th></tr></thead><tbody>{channelRows.map(row=><tr key={row.name}><td>{row.name}</td><td>{row.count}</td><td>{row.response}%</td><td>{row.offer}%</td></tr>)}</tbody></table></article><article className="panel span-panel"><div className="panel-head"><div><span className="section-kicker">DIRECTION</span><h2>行业与岗位成功机会</h2></div></div><div className="direction-grid">{[{title:"行业",rows:distributions.industry},{title:"岗位",rows:distributions.job}].map(group=><div key={group.title}><h3>{group.title}</h3>{group.rows.slice(0,8).map(([name,count])=>{const apps=applications.filter(a=>(group.title==="行业"?a.industry:a.jobCategory||"未填写")===name);const offers=apps.filter(a=>a.stage==="Offer"||a.result==="Offer").length;return <div className="direction-row" key={name}><span>{name}</span><div><i style={{width:`${count/Math.max(1,group.rows[0]?.[1]||1)*100}%`}}/></div><b>{count} 投 · {offers} Offer</b></div>})}</div>)}</div></article></div></section>}

function TimelinePage({events,applications}:{events:TimelineEvent[];applications:Application[]}) {const appMap=Object.fromEntries(applications.map(a=>[a.id,a]));const grouped=[...events].sort((a,b)=>b.occurredAt.localeCompare(a.occurredAt)).reduce<Record<string,TimelineEvent[]>>((acc,event)=>{const key=event.occurredAt.slice(0,7)||"未知月份";(acc[key]??=[]).push(event);return acc;},{});return <section className="page"><div className="page-head"><div><p>按时间回顾投递、笔试、面试和 Offer 里程碑。</p></div></div>{Object.keys(grouped).length?<div className="master-timeline">{Object.entries(grouped).map(([month,items])=><section key={month}><h2>{month.replace("-"," 年 ")} 月</h2><div>{items.map((event,index)=>{const app=appMap[event.applicationId];const milestone=event.title.includes("Offer")||index===items.length-1;return <article className={milestone?"milestone":""} key={event.id}><time>{formatDate(event.occurredAt)}</time><i>{milestone?"★":""}</i><div><span>{event.type}</span><h3>{app?`${app.company} · ${app.role}`:"已删除的投递"}</h3><p>{event.title}</p>{event.notes&&<small>{event.notes}</small>}</div></article>})}</div></section>)}</div>:<Empty icon="│" title="时间线还没有内容" copy="新增投递并推进状态后，这里会自动记录你的秋招历程。"/>}</section>}
